/// Detect language name from a file extension (without leading dot).
///
/// Returns `null` for unrecognized extensions. The match is case-insensitive.
pub fn detect_language_from_extension(ext: String) -> Option<String> {
    tree_sitter_language_pack::detect_language_from_extension(&ext).map(|v| v.to_string())
}

/// Detect language name from a file path.
///
/// Extracts the file extension and looks it up. Returns `null` if the
/// path has no extension or the extension is not recognized.
pub fn detect_language_from_path(path: String) -> Option<String> {
    tree_sitter_language_pack::detect_language_from_path(&path).map(|v| v.to_string())
}

/// Detect language name from file content using the shebang line (`#!`).
///
/// Inspects only the first line of `content`. If it begins with `#!`, the
/// interpreter name is extracted and mapped to a language name.
///
/// Handles common patterns:
///
/// - `#!/usr/bin/env python3` → `"python"`
/// - `#!/bin/bash` → `"bash"`
/// - `#!/usr/bin/env node` → `"javascript"`
///
/// The `-S` flag accepted by some `env` implementations is skipped automatically.
/// Version suffixes (e.g. `python3.11`, `ruby3.2`) are stripped before matching.
///
/// Returns `null` when content does not start with `#!`, the shebang is
/// malformed, or the interpreter is not recognised.
pub fn detect_language_from_content(content: String) -> Option<String> {
    tree_sitter_language_pack::detect_language_from_content(&content).map(|v| v.to_string())
}

/// Get the highlights query for a language, if bundled.
///
/// Returns the contents of `highlights.scm` as a static string, or `null`
/// if no highlights query is bundled for this language.
pub fn get_highlights_query(language: String) -> Option<String> {
    tree_sitter_language_pack::get_highlights_query(&language).map(|v| v.to_string())
}

/// Get the injections query for a language, if bundled.
///
/// Returns the contents of `injections.scm` as a static string, or `null`
/// if no injections query is bundled for this language.
pub fn get_injections_query(language: String) -> Option<String> {
    tree_sitter_language_pack::get_injections_query(&language).map(|v| v.to_string())
}

/// Get the locals query for a language, if bundled.
///
/// Returns the contents of `locals.scm` as a static string, or `null`
/// if no locals query is bundled for this language.
pub fn get_locals_query(language: String) -> Option<String> {
    tree_sitter_language_pack::get_locals_query(&language).map(|v| v.to_string())
}

/// Get a tree-sitter `Language` by name using the global registry.
///
/// Resolves language aliases (e.g., `"shell"` maps to `"bash"`).
/// When the `download` feature is enabled (default), automatically downloads
/// the parser from GitHub releases if not found locally.
///
/// **Errors:**
///
/// Returns `Error.LanguageNotFound` if the language is not recognized,
/// or `Error.Download` if auto-download fails.
pub fn get_language(name: String) -> Result<Language, String> {
    tree_sitter_language_pack::get_language(&name)
        .map(|inner| Language { inner })
        .map_err(|e| e.to_string())
}

/// Get a `Parser` pre-configured for the given language.
///
/// This is a convenience function that calls `get_language` and configures
/// a new parser in one step.
///
/// **Errors:**
///
/// Returns `Error.LanguageNotFound` if the language is not recognized, or
/// `Error.ParserSetup` if the language cannot be applied to the parser.
pub fn get_parser(name: String) -> Result<Parser, String> {
    tree_sitter_language_pack::get_parser(&name)
        .map(|inner| Parser { inner })
        .map_err(|e| e.to_string())
}

/// Detect language name from a file path or extension.
///
/// This compatibility alias matches the pre-Alef Python binding API.
pub fn detect_language(path: String) -> Option<String> {
    tree_sitter_language_pack::detect_language(&path).map(|v| v.to_string())
}

/// List all available language names (sorted, deduplicated, includes aliases).
///
/// Returns names of both statically compiled and dynamically loadable languages,
/// plus any configured aliases.
pub fn available_languages() -> Vec<String> {
    tree_sitter_language_pack::available_languages()
        .into_iter()
        .map(|s| s.to_string())
        .collect::<Vec<_>>()
}

/// Check if a language is available by name or alias.
///
/// Returns `true` if the language can be loaded (statically compiled,
/// dynamically available, or a known alias for one of these).
pub fn has_language(name: String) -> bool {
    tree_sitter_language_pack::has_language(&name) as bool
}

/// Return the number of available languages.
///
/// Includes statically compiled languages, dynamically loadable languages,
/// and aliases.
pub fn language_count() -> i64 {
    tree_sitter_language_pack::language_count() as i64
}

/// Process source code and extract file intelligence using the global registry.
///
/// Parses the source with tree-sitter and extracts metrics, structure, imports,
/// exports, comments, docstrings, symbols, diagnostics, and/or chunks based on
/// the flags set in `ProcessConfig`.
///
/// **Errors:**
///
/// Returns an error if the language is not found or parsing fails.
pub fn process(source: String, config: ProcessConfig) -> Result<ProcessResult, String> {
    tree_sitter_language_pack::process(&source, &tree_sitter_language_pack::ProcessConfig::from(config))
        .map(ProcessResult::from)
        .map_err(|e| e.to_string())
}

/// Initialize the language pack with the given configuration.
///
/// Applies any custom cache directory, then downloads all languages and groups
/// specified in the config. This is the recommended entry point when you want
/// to pre-warm the cache before use.
///
/// **Errors:**
///
/// Returns an error if configuration cannot be applied or if downloads fail.
pub fn init(config: PackConfig) -> Result<(), String> {
    tree_sitter_language_pack::init(&tree_sitter_language_pack::PackConfig::from(config))
        .map(|v| v)
        .map_err(|e| e.to_string())
}

/// Apply download configuration without downloading anything.
///
/// Use this to set a custom cache directory before the first call to
/// `get_language` or any download function. Changing the cache dir
/// after languages have been registered has no effect on already-loaded
/// languages.
///
/// **Errors:**
///
/// Returns an error if the lock cannot be acquired.
pub fn configure(config: PackConfig) -> Result<(), String> {
    tree_sitter_language_pack::configure(&tree_sitter_language_pack::PackConfig::from(config))
        .map(|v| v)
        .map_err(|e| e.to_string())
}

/// Download specific languages to the local cache.
///
/// Returns the number of requested languages available after the call. Already
/// compiled or cached languages are included in the count.
///
/// **Errors:**
///
/// Returns an error if any language is not available in the manifest or if
/// the download fails.
pub fn download(names: Vec<String>) -> Result<i64, String> {
    tree_sitter_language_pack::download(&names)
        .map(|v| v as i64)
        .map_err(|e| e.to_string())
}

/// Download all available languages from the remote manifest.
///
/// Downloads the platform bundle and extracts every library it contains.
/// Languages that appear in the manifest but are absent from the bundle
/// (e.g. grammars that failed to compile at release time) are silently
/// skipped — they are not treated as an error.
///
/// Returns the total number of languages now available (statically compiled
/// plus downloaded and cached).
///
/// **Errors:**
///
/// Returns an error if the manifest cannot be fetched or the bundle download fails.
pub fn download_all() -> Result<i64, String> {
    tree_sitter_language_pack::download_all()
        .map(|v| v as i64)
        .map_err(|e| e.to_string())
}

/// Download every language in a named group (e.g. `"web"`, `"data"`).
///
/// Groups are defined in the remote manifest and let you ensure a curated
/// set of related grammars in one call instead of listing each name to
/// `download`. Already-cached languages are skipped.
///
/// Returns the total number of languages now available (statically compiled
/// plus downloaded and cached).
///
/// **Errors:**
///
/// Returns an error if the manifest cannot be fetched, the group is unknown,
/// or any constituent language fails to download.
pub fn download_group(name: String) -> Result<i64, String> {
    tree_sitter_language_pack::download_group(&name)
        .map(|v| v as i64)
        .map_err(|e| e.to_string())
}

/// Return all language names available in the remote manifest (305).
///
/// Fetches (and caches) the remote manifest to discover the full list of
/// downloadable languages. Use `downloaded_languages` to list what is
/// already cached locally.
///
/// **Errors:**
///
/// Returns an error if the manifest cannot be fetched.
pub fn manifest_languages() -> Result<Vec<String>, String> {
    tree_sitter_language_pack::manifest_languages()
        .map(|v| v.into_iter().map(|s| s.to_string()).collect::<Vec<_>>())
        .map_err(|e| e.to_string())
}

/// Return languages that are already downloaded and cached locally.
///
/// Does not perform any network requests. Returns an empty list if the
/// cache directory does not exist or cannot be read.
pub fn downloaded_languages() -> Vec<String> {
    tree_sitter_language_pack::downloaded_languages()
        .into_iter()
        .map(|s| s.to_string())
        .collect::<Vec<_>>()
}

/// Delete all cached parser shared libraries.
///
/// Resets the cache registration so the next call to `get_language` or
/// a download function will re-register the (now empty) cache directory.
///
/// **Errors:**
///
/// Returns an error if the cache directory cannot be removed.
pub fn clean_cache() -> Result<(), String> {
    tree_sitter_language_pack::clean_cache()
        .map(|v| v)
        .map_err(|e| e.to_string())
}

/// Return the effective cache directory path.
///
/// This is either the custom path set via `configure` / `init` or the
/// default: `~/.cache/tree-sitter-language-pack/v{version}/libs/`.
///
/// **Errors:**
///
/// Returns an error if the system cache directory cannot be determined.
pub fn cache_dir() -> Result<String, String> {
    tree_sitter_language_pack::cache_dir()
        .map(|v| v.to_string())
        .map_err(|e| e.to_string())
}

